viewof funcText = Inputs.text({
  label: "Function f(x)",
  value: "sin(x)",
  placeholder: "e.g. sin(x), x^2, exp(-x^2)"
})

viewof xmin = Inputs.number({
  label: "x minimum",
  value: -10,
  step: 0.1
})

viewof xmax = Inputs.number({
  label: "x maximum",
  value: 10,
  step: 0.1
})

viewof npoints = Inputs.range([100, 3000], {
  label: "Number of points",
  value: 1000,
  step: 100
})

viewof autoY = Inputs.toggle({
  label: "Auto y-axis",
  value: true
})

viewof ymin = Inputs.number({
  label: "Manual y minimum",
  value: -2,
  step: 0.1
})

viewof ymax = Inputs.number({
  label: "Manual y maximum",
  value: 2,
  step: 0.1
})

Plot


Code
compiledFunction = {
  try {
    return math.compile(funcText);
  } catch (error) {
    return null;
  }
}









Code
errorMessage = {
  try {
    math.compile(funcText);
    return "";
  } catch (error) {
    return error.message;
  }
}









Code
html`&lt;p style="color:red;"&gt;${errorMessage}&lt;/p&gt;`









Code
data = {
  const points = [];

  if (!compiledFunction || xmax &lt;= xmin) {
    return points;
  }

  const dx = (xmax - xmin) / (npoints - 1);

  for (let i = 0; i &lt; npoints; i++) {
    const x = xmin + i * dx;

    let y;
    try {
      y = compiledFunction.evaluate({x});
    } catch (error) {
      y = NaN;
    }

    if (Number.isFinite(y)) {
      points.push({x, y});
    }
  }

  return points;
}









Code
yDomain = {
  if (autoY || data.length === 0) {
    return undefined;
  } else {
    return [ymin, ymax];
  }
}









Code
Plot.plot({
  width: 750,
  height: 450,
  grid: true,
  x: {
    label: "x",
    domain: [xmin, xmax]
  },
  y: {
    label: "f(x)",
    domain: yDomain
  },
  marks: [
    Plot.line(data, {
      x: "x",
      y: "y",
      stroke: "steelblue",
      strokeWidth: 2
    }),
    Plot.ruleY([0], {stroke: "black", strokeOpacity: 0.4}),
    Plot.ruleX([0], {stroke: "black", strokeOpacity: 0.4})
  ]
})
